INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 44, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 16, "人助けが大好き！　前向き格闘娘", "東山奈央", "A", "人助け、応援", 155, "トゥインクルウィッシュ", 27, "獣人族", 100101, "ヒヨリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 47, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 17, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "O", "料理、人間観察", 158, "トゥインクルウィッシュ", 5, "ヒューマン", 100201, "ユイ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 46, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 18, "クールで何事にも真っ直ぐな剣士", "早見沙織", "B", "読書、乗馬、お茶", 163, "トゥインクルウィッシュ", 12, "魔族", 100301, "レイ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 27, 0, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 8, 9, "探検好きのイタズラっ子", "諸星すみれ", "O", "いたずら、探検", 128, "リトルリリカル", 10, "ヒューマン", 100401, "ミソギ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 40, 0, "？？？", 11, 12, "ヒーローに憧れる騎士見習いの少女", "下田麻美", "O", "ヒーローごっこ", 146, "王宮騎士団（NIGHTMARE）", 25, "獣人族", 100501, "マツリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 42, 0, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 11, 13, "甘え上手なみんなの人気者", "浅倉杏美", "O", "サックス", 150, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 100601, "アカリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 32, 0, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 1, 14, "プリン大好きゴースト娘", "雨宮天", "B", "プリンを食べること", 130, "悪魔偽王国軍（ディアボロス）", 23, "魔族", 100701, "ミヤコ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 40, 0, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 10, 14, "ボクは誰よりも美しい", "大空直美", "AB", "鏡で自分を見ること", 150, "ヴァイスフリューゲル　ランドソル支部", 10, "エルフ", 100801, "ユキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 45, 0, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 17, "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "A", "小説執筆", 159, "トワイライトキャラバン", 5, "魔族", 100901, "アンナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 42, 0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 16, "マホマホ王国のプリンセス", "内田真礼", "O", "空想、ぬいぐるみ集め", 155, "自警団（カォン）", 22, "獣人族", 101001, "マホ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 44, 0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 15, "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "A", "お裁縫", 156, "ラビリンス", 25, "ヒューマン", 101101, "リノ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 46, 0, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 12, 17, "みんなのために超能力を使う眠り姫", "大橋彩香", "A", "妹と遊ぶこと、二度寝、昼寝、早寝", 156, "フォレスティエ", 24, "エルフ", 101201, "ハツネ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 55, 0, "", 8, 18, "オタク全開な魔法少女", "佳村はるか", "O", "読書、魔法", 166, "トワイライトキャラバン", 21, "魔族", 101301, "ナナカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 41, 0, "test", 11, 15, "頭脳明晰な美少女名探偵", "水瀬いのり", "AB", "読書、推理", 152, "自警団（カォン）", 3, "獣人族", 101401, "カスミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 54, 0, "test", 9, 21, "母性溢れる優しいみんなの「ミサト先生」", "國府田マリ子", "O", "絵本作り", 165, "フォレスティエ", 5, "エルフ", 101501, "ミサト");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 48, 0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 4, 17, "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "O", "ファッション", 167, "ルーセント学院", 10, "魔族", 101601, "スズナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 53, 0, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 7, 17, "いつでも「なんくるないさ～」な天然娘", "高森奈津美", "A", "踊り、空手", 158, "自警団（カォン）", 7, "獣人族", 101701, "カオリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 52, 0, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 8, 23, "多くの男性を魅了する無垢な女教師", "伊藤静", "B", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 162, "ルーセント学院", 14, "魔族", 101801, "イオ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 21, 0, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 4, 10, "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "O", "かわいいもの集め", 117, "リトルリリカル", 3, "獣人族", 102001, "ミミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 40, 0, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 6, 12, "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "B", "観劇、おままごと", 150, "サレンディア救護院", 9, "ヒューマン", 102101, "クルミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 40, 0, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 11, 13, "人見知りであまのじゃくな女の子", "原紗友里", "O", "ゲーム全般", 150, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 102201, "ヨリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 38, 0, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 5, 14, "ぷうきちといつも一緒！", "芹澤優", "B", "屋内でできる遊び", 148, "サレンディア救護院", 10, "ヒューマン", 102301, "アヤネ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 12, 15, "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "O", "ご奉仕", 154, "サレンディア救護院", 12, "ヒューマン", 102501, "スズメ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 42, 0, "test", 1, 17, "遊びと睡眠が何より大事なぐうたら娘", "小岩井ことり", "B", "あんパン", 144, "牧場（エリザベスパーク）", 1, "獣人族", 102601, "リン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 43, 0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 16, "運命の相手に一途すぎる乙女", "橋本ちなみ", "B", "実験、裁縫、料理", 154, "トワイライトキャラバン", 30, "魔族", 102701, "エリコ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 17, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "A", "経営、お茶会", 156, "サレンディア救護院", 4, "エルフ", 102801, "サレン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 40, 0, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 1, 17, "歌って踊れる大人気アイドル", "日笠陽子", "B", "舞台鑑賞、ダンス", 157, "カルミナ", 24, "ヒューマン", 102901, "ノゾミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 51, 0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 16, "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "O", "忍法開発", 163, "ヴァイスフリューゲル　ランドソル支部", 31, "ヒューマン", 103001, "ニノン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 42, 0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 18, "占いが得意な霊能少女", "大坪由佳", "AB", "占い", 157, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 103101, "シノブ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 45, 0, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 3, 18, "一人前の商人を目指すパワフルお嬢様", "松嵜麗", "AB", "慈善事業", 157, "メルクリウス財団", 12, "ヒューマン", 103201, "アキノ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 35, 0, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 3, 20, "みんなを笑顔にするお笑い牧場主", "新田恵海", "B", "漫才", 142, "牧場（エリザベスパーク）", 3, "ヒューマン", 103301, "マヒル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 55, 0, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 22, "純情でほっとけない大人の女性", "今井麻美", "A", "ウインドーショッピング", 164, "メルクリウス財団", 16, "エルフ", 103401, "ユカリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 21, 0, "test", 2, 8, "礼儀正しくしっかり者のちびっ子優等生", "小倉唯", "A", "お勉強", 118, "リトルリリカル", 2, "エルフ", 103601, "キョウカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 43, 0, "test", 8, 13, "義理堅くてからかい好きな剣術少女", "茅原実里", "A", "剣術、年長者をからかう", 149, "王宮騎士団（NIGHTMARE）", 11, "ヒューマン", 103701, "トモ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 40, 0, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11, 14, "読書が趣味の病弱少女", "小清水亜美", "A", "読書、お散歩", 153, "牧場（エリザベスパーク）", 3, "獣人族", 103801, "シオリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 44, 0, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 6, 13, "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "AB", "友達作りのイメトレ", 158, "フォレスティエ", 6, "エルフ", 104001, "アオイ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 46, 0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 17, "人々を守るために歌う、唱喚士の少女", "福原綾香", "O", "各種楽器", 163, "カルミナ", 3, "ヒューマン", 104201, "チカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 54, 0, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 8, 17, "男勝りで情に厚いワイルド娘", "小松未可子", "O", "お菓子作り", 168, "自警団（カォン）", 9, "獣人族", 104301, "マコト");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 50, 0, "test", 5, "??", "かつては夜を支配した最強の吸血鬼", "丹下桜", "A", "世界征服", 172, "悪魔偽王国軍（ディアボロス）", 5, "魔族", 104401, "イリヤ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 49, 0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 18, "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "AB", "小説を読むこと", 157, "ヴァイスフリューゲル　ランドソル支部", 19, "ヒューマン", 104501, "クウカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 48, 0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 19, "弱きを助け強きをくじく猫娘", "沼倉愛美", "AB", "猫とたわむれること", 158, "メルクリウス財団", 1, "獣人族", 104601, "タマキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 50, 0, "？？？", 10, 25, "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "A", "格闘技、湯浴み", 171, "王宮騎士団（NIGHTMARE）", 25, "ヒューマン", 104701, "ジュン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 49, 0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 20, "仕事も私事も効率優先な傭兵少女", "田所あずさ", "O", "傭兵などのアルバイト", 163, "メルクリウス財団", 11, "ヒューマン", 104801, "ミフユ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 54, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 18, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "O", "家事全般", 168, "ラビリンス", 24, "ヒューマン", 104901, "シズル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 22, 0, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 1, 11, "ちょっとおませな恋に恋する女の子", "久野美咲", "A", "ファッション誌鑑賞、コスメ集め", 120, "ルーセント学院", 3, "魔族", 105001, "ミサキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 53, 0, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 3, 27, "実験が趣味の危険な科学者", "三石琴乃", "A", "研究、実験", 166, "トワイライトキャラバン", 7, "ヒューマン", 105101, "ミツキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 100, 0, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 3, 17, "乙女チックなもふもふアニマル", "徳井青空", "A", "毛繕い、お喋り", 150, "牧場（エリザベスパーク）", 14, "獣人族", 105201, "リマ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 33, 0, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 7, 17, "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "A", "お菓子屋通い", 140, "ヴァイスフリューゲル　ランドソル支部", 28, "ヒューマン", 105301, "モニカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 45, 0, "test", 9, 14, "ファッション大好きなキュートガール", "木戸衣吹", "AB", "裁縫", 153, "カルミナ", 7, "ヒューマン", 105401, "ツムギ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 43, 0, "test", 4, 16, "どこまでも一途に慕う、純情乙女", "大関英里", "O", "観察", 155, "ヴァイスフリューゲル　ランドソル支部", 7, "エルフ", 105501, "アユミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 54, 0, "test", 7, 25, "人情味溢れる粋でいなせな「姉御」", "佐藤利奈", "B", "釣り", 167, "トワイライトキャラバン", 11, "ヒューマン", 105601, "ルカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 45, 0, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 3, 17, "空への冒険を夢見る騎空士の少女", "金元寿子", "O", "冒険、おしゃべり", 156, "？？？", 10, "ヒューマン", 105701, "ジータ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 46, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 17, "いつも元気な腹ペコ少女", "M・A・O", "O", "食べ歩き、料理", 156, "美食殿", 31, "ヒューマン", 105801, "ペコリーヌ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 35, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11, "主を慕う、小さなガイド役", "伊藤美来", "B", "瞑想、動植物の飼育", 140, "美食殿", 11, "エルフ", 105901, "コッコロ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 39, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 14, "行き倒れの謎のネコミミ魔法使い", "立花理香", "A", "猫と遊ぶ", 152, "美食殿", 2, "獣人族", 106001, "キャル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 40, 0, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 8, 16, "さまよえる謎の少女", "潘めぐみ", "O", "冒険、思い出話", 148, "？？？", 11, "ヒューマン", 106101, "ムイミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 42, 0, "", 6, 15, "森番を目指すエルフの少女", "優木かな", "O", "キレイな葉っぱを集めること", 155, "？？？", 17, "エルフ", 106301, "アリサ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "???", 0, "", 12, 14, "記憶喪失のドラゴン娘", "近藤玲奈", "B", "読書、ストレッチ", 147, "美食殿", 14, "ドラゴン族", 106401, "シェフィ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 6, 16, "拳で語る喧嘩屋ドラゴン少女", "小市眞琴", "B", "格闘技", 156, "ドラゴンズネスト", 25, "ドラゴン族", 106501, "カヤ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 9, 13, "口が達者なヘタレドラゴン", "藤田茜", "AB", "ゲーム", 145, "ドラゴンズネスト", 29, "ドラゴン族", 106601, "イノリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 4, 25, "妖しい微笑で全てを見透かす臥竜の頭領", "大西沙織", "O", "絵画、読書", 168, "ドラゴンズネスト", 17, "ドラゴン族", 106701, "ホマレ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "??", 0, "", 7, 25, "秘密結社ラビリンスの『迷宮女王』", "沢城みゆき", "AB", "人間観察", 160, "ラビリンス", 25, "ヒューマン", 106801, "ラビリスタ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 7, 29, "謎に包まれたランドソルの主", "蒼井翔太", "AB", "占い、支配", 166, "？？？", 1, "獣人族", 106901, "カイザーインサイト");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 3, 24, "研究所に隠れ住む物静かなお姉さん", "井口裕香", "O", "物真似、芸術鑑賞", 149, "？？？", 24, "エルフ", 107001, "ネネカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "??", 0, "", 2, 27, "傍若無人な王宮騎士団副団長", "たかはし智秋", "O", "強敵との闘争", 165, "王宮騎士団（NIGHTMARE）", 7, "ヒューマン", 107101, "クリスティーナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 46, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 17, "いつも元気な腹ペコ少女", "M・A・O", "O", "食べ歩き、料理", 156, "美食殿", 31, "ヒューマン", 107501, "ペコリーヌ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 35, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11, "主を慕う、小さなガイド役", "伊藤美来", "B", "瞑想、動植物の飼育", 140, "美食殿", 11, "エルフ", 107601, "コッコロ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 12, 15, "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "O", "ご奉仕", 154, "サレンディア救護院", 12, "ヒューマン", 107701, "スズメ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 39, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 14, "行き倒れの謎のネコミミ魔法使い", "立花理香", "A", "猫と遊ぶ", 152, "美食殿", 2, "獣人族", 107801, "キャル（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 48, 0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 19, "弱きを助け強きをくじく猫娘", "沼倉愛美", "AB", "猫とたわむれること", 158, "メルクリウス財団", 1, "獣人族", 107901, "タマキ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 49, 0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 20, "仕事も私事も効率優先な傭兵少女", "田所あずさ", "O", "傭兵などのアルバイト", 163, "メルクリウス財団", 11, "ヒューマン", 108001, "ミフユ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 42, 0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 18, "占いが得意な霊能少女", "大坪由佳", "AB", "占い", 157, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 108101, "シノブ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 32, 0, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 1, 14, "プリン大好きゴースト娘", "雨宮天", "B", "プリンを食べること", 130, "悪魔偽王国軍（ディアボロス）", 23, "魔族", 108201, "ミヤコ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 22, 0, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 1, 11, "ちょっとおませな恋に恋する女の子", "久野美咲", "A", "ファッション誌鑑賞、コスメ集め", 120, "ルーセント学院", 3, "魔族", 108301, "ミサキ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 46, 0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 17, "人々を守るために歌う、唱喚士の少女", "福原綾香", "O", "各種楽器", 163, "カルミナ", 3, "ヒューマン", 108401, "チカ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 40, 0, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 6, 12, "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "B", "観劇、おままごと", 150, "サレンディア救護院", 9, "ヒューマン", 108501, "クルミ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 38, 0, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 5, 14, "ぷうきちといつも一緒！", "芹澤優", "B", "屋内でできる遊び", 148, "サレンディア救護院", 10, "ヒューマン", 108601, "アヤネ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 44, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 16, "人助けが大好き！　前向き格闘娘", "東山奈央", "A", "人助け、応援", 155, "トゥインクルウィッシュ", 27, "獣人族", 108701, "ヒヨリ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 47, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 17, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "O", "料理、人間観察", 158, "トゥインクルウィッシュ", 5, "ヒューマン", 108801, "ユイ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 46, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 18, "クールで何事にも真っ直ぐな剣士", "早見沙織", "B", "読書、乗馬、お茶", 163, "トゥインクルウィッシュ", 12, "魔族", 108901, "レイ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 43, 0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 16, "運命の相手に一途すぎる乙女", "橋本ちなみ", "B", "実験、裁縫、料理", 154, "トワイライトキャラバン", 30, "魔族", 109001, "エリコ（バレンタイン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 54, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 18, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "O", "家事全般", 168, "ラビリンス", 24, "ヒューマン", 109101, "シズル（バレンタイン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 55, 0, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 12, 17, "英霊と契約を結んだマナリアの天才王女", "日笠陽子", "AB", "読書", 156, "？？？", 1, "ヒューマン", 109201, "アン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 45, 0, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 2, 16, "マナリア魔法学院の新入生", "こやまきみこ", "O", "食べること、眠ること", 144, "？？？", 4, "ヒューマン", 109301, "ルゥ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 67, 0, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 11, 17, "人を超越した力を有す心優しい竜姫", "福原綾香", "B", "ピアノ", 167, "？？？", 3, "半人半竜", 109401, "グレア");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 49, 0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 18, "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "AB", "小説を読むこと", 157, "ヴァイスフリューゲル　ランドソル支部", 19, "ヒューマン", 109501, "クウカ（オーエド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 51, 0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 16, "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "O", "忍法開発", 163, "ヴァイスフリューゲル　ランドソル支部", 31, "ヒューマン", 109601, "ニノン（オーエド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 2, 17, "鬼がかりの万能妹メイド", "水瀬いのり", "?", "演劇鑑賞、詩文", 154, "？？？", 2, "鬼族", 109701, "レム");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 2, 17, "毒舌系鬼姉メイド", "村川梨衣", "?", "読書", 154, "？？？", 2, "鬼族", 109801, "ラム");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 9, "??", "銀髪のおっとりハーフエルフ", "高橋李依", "?", "パックの毛繕い、勉強", 164, "？？？", 23, "ハーフエルフ", 109901, "エミリア");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 48, 0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 4, 17, "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "O", "ファッション", 167, "ルーセント学院", 10, "魔族", 110001, "スズナ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 52, 0, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 8, 23, "多くの男性を魅了する無垢な女教師", "伊藤静", "B", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 162, "ルーセント学院", 14, "魔族", 110101, "イオ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 22, 0, "", 1, 11, "ちょっとおませな恋に恋する女の子", "久野美咲", "A", "ファッション誌鑑賞、コスメ集め", 120, "ルーセント学院", 3, "魔族", 110201, "ミサキ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 17, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "A", "経営、お茶会", 156, "サレンディア救護院", 4, "エルフ", 110301, "サレン（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 54, 0, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 8, 17, "男勝りで情に厚いワイルド娘", "小松未可子", "O", "お菓子作り", 168, "自警団（カォン）", 9, "獣人族", 110401, "マコト（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 53, 0, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 7, 17, "いつでも「なんくるないさ～」な天然娘", "高森奈津美", "A", "踊り、空手", 158, "自警団（カォン）", 7, "獣人族", 110501, "カオリ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 42, 0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 16, "マホマホ王国のプリンセス", "内田真礼", "O", "空想、ぬいぐるみ集め", 155, "自警団（カォン）", 22, "獣人族", 110601, "マホ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 44, 0, "", 6, 13, "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "AB", "友達作りのイメトレ", 158, "フォレスティエ", 6, "エルフ", 110701, "アオイ（編入生）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 42, 0, "", 8, 17, "ダウンタウン育ちのダウナー系エルフ", "種﨑敦美", "O", "ダーツ", 154, "聖テレサ女学院（なかよし部）", 7, "エルフ", 110801, "クロエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 46, 0, "", 9, 16, "自由奔放ナチュラル無礼な現代っ子", "佐倉綾音", "O", "ダンス、カラオケ", 156, "聖テレサ女学院（なかよし部）", 15, "ヒューマン", 110901, "チエル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 36, 0, "", 2, 18, "書庫に眠れる小さな賢人", "小原好美", "O", "読書", 142, "聖テレサ女学院（なかよし部）", 28, "ヒューマン", 111001, "ユニ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 21, 0, "", 2, 8, "礼儀正しくしっかり者のちびっ子優等生", "小倉唯", "A", "お勉強", 118, "リトルリリカル", 2, "エルフ", 111101, "キョウカ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 27, 0, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 8, 9, "探検好きのイタズラっ子", "諸星すみれ", "O", "いたずら、探検", 128, "リトルリリカル", 10, "ヒューマン", 111201, "ミソギ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 21, 0, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 4, 10, "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "O", "かわいいもの集め", 117, "リトルリリカル", 3, "獣人族", 111301, "ミミ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 28, 0, "", 1, "??", "おともだちを探す死霊術師の少女", "小倉唯", "?", "「おともだち」を探すこと", 142, "？？？", 8, "ヒューマン", 111401, "ルナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "??", 0, "", 2, 27, "傍若無人な王宮騎士団副団長", "たかはし智秋", "O", "強敵との闘争", 165, "王宮騎士団（NIGHTMARE）", 7, "ヒューマン", 111501, "クリスティーナ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 40, 0, "", 1, 17, "歌って踊れる大人気アイドル", "日笠陽子", "B", "舞台鑑賞、ダンス", 157, "カルミナ", 24, "ヒューマン", 111601, "ノゾミ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 50, 0, "", 5, "??", "かつては夜を支配した最強の吸血鬼", "丹下桜", "A", "世界征服", 172, "悪魔偽王国軍（ディアボロス）", 5, "魔族", 111701, "イリヤ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 46, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 17, "いつも元気な腹ペコ少女", "M・A・O", "O", "食べ歩き、料理", 156, "美食殿", 31, "ヒューマン", 111801, "ぺコリーヌ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 35, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11, "主を慕う、小さなガイド役", "伊藤美来", "B", "瞑想、動植物の飼育", 140, "美食殿", 11, "エルフ", 111901, "コッコロ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 39, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 14, "行き倒れの謎のネコミミ魔法使い", "立花理香", "A", "猫と遊ぶ", 152, "美食殿", 2, "獣人族", 112001, "キャル（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 12, 15, "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "O", "ご奉仕", 154, "サレンディア救護院", 12, "ヒューマン", 112101, "スズメ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 41, 0, "", 11, 15, "頭脳明晰な美少女名探偵", "水瀬いのり", "AB", "読書、推理", 152, "自警団（カォン）", 3, "獣人族", 112201, "カスミ（マジカル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 40, 0, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11, 14, "読書が趣味の病弱少女", "小清水亜美", "A", "読書、お散歩", 153, "牧場（エリザベスパーク）", 3, "獣人族", 112301, "シオリ（マジカル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100, 45, 0, "", 4, 17, "弾ける笑顔！　アイドルを夢見る女の子", "大橋彩香", "O", "友達と長話", 159, "ニュージェネレーションズ", 24, "ヒューマン", 112401, "ウヅキ（デレマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100, 44, 0, "", 8, 15, "クールビューティーな「蒼の剣士」", "福原綾香", "B", "犬の散歩", 165, "ニュージェネレーションズ", 10, "ヒューマン", 112501, "リン（デレマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100, 46, 0, "", 12, 15, "スーパースターを目指す元気娘☆☆★", "原紗友里", "B", "ショッピング", 161, "ニュージェネレーションズ", 1, "ヒューマン", 112601, "ミオ（デレマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 42, 0, "", 1, 17, "遊びと睡眠が何より大事なぐうたら娘", "小岩井ことり", "B", "あんパン", 144, "牧場（エリザベスパーク）", 1, "獣人族", 112701, "リン（レンジャー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 35, 0, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 3, 20, "みんなを笑顔にするお笑い牧場主", "新田恵海", "B", "漫才", 142, "牧場（エリザベスパーク）", 3, "ヒューマン", 112801, "マヒル（レンジャー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 44, 0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 15, "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "A", "お裁縫", 156, "ラビリンス", 25, "ヒューマン", 112901, "リノ（ワンダー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 43, 0, "", 4, 16, "どこまでも一途に慕う、純情乙女", "大関英里", "O", "観察", 155, "ヴァイスフリューゲル　ランドソル支部", 7, "エルフ", 113001, "アユミ（ワンダー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 54, 0, "", 7, 25, "人情味溢れる粋でいなせな「姉御」", "佐藤利奈", "B", "釣り", 167, "トワイライトキャラバン", 11, "ヒューマン", 113101, "ルカ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 45, 0, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 17, "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "A", "小説執筆", 159, "トワイライトキャラバン", 5, "魔族", 113201, "アンナ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 55, 0, "", 8, 18, "オタク全開な魔法少女", "佳村はるか", "O", "読書、魔法", 166, "トワイライトキャラバン", 21, "魔族", 113301, "ナナカ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 46, 0, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 12, 17, "みんなのために超能力を使う眠り姫", "大橋彩香", "A", "妹と遊ぶこと、二度寝、昼寝、早寝", 156, "フォレスティエ", 24, "エルフ", 113401, "ハツネ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 54, 0, "", 9, 21, "母性溢れる優しいみんなの「ミサト先生」", "國府田マリ子", "O", "絵本作り", 165, "フォレスティエ", 5, "エルフ", 113501, "ミサト（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 50, 0, "", 10, 25, "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "A", "格闘技、湯浴み", 171, "王宮騎士団（NIGHTMARE）", 25, "ヒューマン", 113601, "ジュン（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 42, 0, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 11, 13, "甘え上手なみんなの人気者", "浅倉杏美", "O", "サックス", 150, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 113701, "アカリ（エンジェル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 40, 0, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 11, 13, "人見知りであまのじゃくな女の子", "原紗友里", "O", "ゲーム全般", 150, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 113801, "ヨリ（エンジェル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 45, 0, "", 9, 14, "ファッション大好きなキュートガール", "木戸衣吹", "AB", "裁縫", 153, "カルミナ", 7, "ヒューマン", 113901, "ツムギ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 46, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 18, "クールで何事にも真っ直ぐな剣士", "早見沙織", "B", "読書、乗馬、お茶", 163, "トゥインクルウィッシュ", 12, "魔族", 114001, "レイ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 40, 0, "", 11, 12, "ヒーローに憧れる騎士見習いの少女", "下田麻美", "O", "ヒーローごっこ", 146, "王宮騎士団（NIGHTMARE）", 25, "獣人族", 114101, "マツリ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 33, 0, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 7, 17, "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "A", "お菓子屋通い", 140, "ヴァイスフリューゲル　ランドソル支部", 28, "ヒューマン", 114201, "モニカ（マジカル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 43, 0, "", 8, 13, "義理堅くてからかい好きな剣術少女", "茅原実里", "A", "剣術、年長者をからかう", 149, "王宮騎士団（NIGHTMARE）", 11, "ヒューマン", 114301, "トモ（マジカル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 45, 0, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 3, 18, "一人前の商人を目指すパワフルお嬢様", "松嵜麗", "AB", "慈善事業", 157, "メルクリウス財団", 12, "ヒューマン", 114401, "アキノ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 17, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "A", "経営、お茶会", 156, "サレンディア救護院", 4, "エルフ", 114501, "サレン（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 55, 0, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 22, "純情でほっとけない大人の女性", "今井麻美", "A", "ウインドーショッピング", 164, "メルクリウス財団", 16, "エルフ", 114601, "ユカリ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 40, 0, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 8, 16, "さまよえる謎の少女", "潘めぐみ", "O", "冒険、思い出話", 148, "？？？", 11, "ヒューマン", 114701, "ムイミ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 3, 24, "研究所に隠れ住む物静かなお姉さん", "井口裕香", "O", "物真似、芸術鑑賞", 149, "？？？", 24, "エルフ", 115001, "ネネカ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 35, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11, "主を慕う、小さなガイド役", "伊藤美来", "B", "瞑想、動植物の飼育", 140, "美食殿", 11, "エルフ", 115501, "コッコロ（儀装束）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 47, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 17, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "O", "料理、人間観察", 158, "トゥインクルウィッシュ", 5, "ヒューマン", 115601, "ユイ（儀装束）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 41, 0, "", 11, 15, "頭脳明晰な美少女名探偵", "水瀬いのり", "AB", "読書、推理", 152, "自警団（カォン）", 3, "獣人族", 115701, "カスミ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 100, 0, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 3, 17, "乙女チックなもふもふアニマル", "徳井青空", "A", "毛繕い、お喋り", 150, "牧場（エリザベスパーク）", 14, "獣人族", 115801, "リマ（シンデレラ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 54, 0, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 8, 17, "男勝りで情に厚いワイルド娘", "小松未可子", "O", "お菓子作り", 168, "自警団（カォン）", 9, "獣人族", 115901, "マコト（シンデレラ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 42, 0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 16, "マホマホ王国のプリンセス", "内田真礼", "O", "空想、ぬいぐるみ集め", 155, "自警団（カォン）", 22, "獣人族", 116001, "マホ（シンデレラ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 42, 0, "", 8, 17, "ダウンタウン育ちのダウナー系エルフ", "種﨑敦美", "O", "ダーツ", 154, "聖テレサ女学院（なかよし部）", 7, "エルフ", 116201, "クロエ（聖学祭）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 46, 0, "", 9, 16, "自由奔放ナチュラル無礼な現代っ子", "佐倉綾音", "O", "ダンス、カラオケ", 156, "聖テレサ女学院（なかよし部）", 15, "ヒューマン", 116301, "チエル（聖学祭）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 36, 0, "", 2, 18, "書庫に眠れる小さな賢人", "小原好美", "O", "読書", 142, "聖テレサ女学院（なかよし部）", 28, "ヒューマン", 116401, "ユニ（聖学祭）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 9, 13, "口が達者なヘタレドラゴン", "藤田茜", "AB", "ゲーム", 145, "ドラゴンズネスト", 29, "ドラゴン族", 116501, "イノリ（タイムトラベル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 6, 16, "拳で語る喧嘩屋ドラゴン少女", "小市眞琴", "B", "格闘技", 156, "ドラゴンズネスト", 25, "ドラゴン族", 116601, "カヤ（タイムトラベル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 44, 0, "", 6, 13, "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "AB", "友達作りのイメトレ", 158, "フォレスティエ", 6, "エルフ", 116701, "アオイ（作業服）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 48, 0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 19, "弱きを助け強きをくじく猫娘", "沼倉愛美", "AB", "猫とたわむれること", 158, "メルクリウス財団", 1, "獣人族", 116801, "タマキ（作業服）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 49, 0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 20, "仕事も私事も効率優先な傭兵少女", "田所あずさ", "O", "傭兵などのアルバイト", 163, "メルクリウス財団", 11, "ヒューマン", 116901, "ミフユ（作業服）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 43, 0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 16, "運命の相手に一途すぎる乙女", "橋本ちなみ", "B", "実験、裁縫、料理", 154, "トワイライトキャラバン", 30, "魔族", 117001, "エリコ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 54, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 18, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "O", "家事全般", 168, "ラビリンス", 24, "ヒューマン", 117101, "シズル（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 40, 0, "", 1, 17, "歌って踊れる大人気アイドル", "日笠陽子", "B", "舞台鑑賞、ダンス", 157, "カルミナ", 24, "ヒューマン", 117201, "ノゾミ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 46, 0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 17, "人々を守るために歌う、唱喚士の少女", "福原綾香", "O", "各種楽器", 163, "カルミナ", 3, "ヒューマン", 117301, "チカ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 45, 0, "", 9, 14, "ファッション大好きなキュートガール", "木戸衣吹", "AB", "裁縫", 153, "カルミナ", 7, "ヒューマン", 117401, "ツムギ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 53, 0, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 3, 27, "実験が趣味の危険な科学者", "三石琴乃", "A", "研究、実験", 166, "トワイライトキャラバン", 7, "ヒューマン", 117501, "ミツキ（オーエド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 40, 0, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 10, 14, "ボクは誰よりも美しい", "大空直美", "AB", "鏡で自分を見ること", 150, "ヴァイスフリューゲル　ランドソル支部", 10, "エルフ", 117601, "ユキ（オーエド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 53, 0, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 7, 17, "いつでも「なんくるないさ～」な天然娘", "高森奈津美", "A", "踊り、空手", 158, "自警団（カォン）", 7, "獣人族", 117701, "カオリ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 51, 0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 16, "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "O", "忍法開発", 163, "ヴァイスフリューゲル　ランドソル支部", 31, "ヒューマン", 117801, "ニノン（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 48, 0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 4, 17, "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "O", "ファッション", 167, "ルーセント学院", 10, "魔族", 117901, "スズナ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 57, 0, "", 9, 26, "忠義に目覚めた女商人", "Lynn", "A", "お金を数えること、悪だくみ", 160, "リッチモンド商工会", 19, "ヒューマン", 118001, "クレジッタ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, 53, 0, "", 12, 20, "静寂を求め歌う陰気少女", "原田彩楓", "O", "歌、読書、詩を書くこと", 165, "レイジ・レギオン", 28, "魔族", 118101, "ランファ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, "??", 0, "", 7, 16, "明朗快活、なれど破滅に流るる溌溂少女", "鬼頭明里", "A", "特に無し", 159, "レイジ・レギオン", 2, "ヒューマン", 118201, "ミソラ");
