INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "???", 0, "", "?", "??", "幻霧に戯れる悪戯好きなガイド妖精", "相坂優歌", "?", "悪戯をすること", "???", "？？？", "?", "？？？", 118601, "ネビア");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 52, 0, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 8, 23, "多くの男性を魅了する無垢な女教師", "伊藤静", "B", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 162, "ルーセント学院", 14, "魔族", 119001, "イオ（ノワール）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 49, 0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 18, "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "AB", "小説を読むこと", 157, "ヴァイスフリューゲル　ランドソル支部", 19, "ヒューマン", 119101, "クウカ（ノワール）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 35, 0, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 3, 20, "みんなを笑顔にするお笑い牧場主", "新田恵海", "B", "漫才", 142, "牧場（エリザベスパーク）", 3, "ヒューマン", 119201, "マヒル（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 44, 0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 15, "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "A", "お裁縫", 156, "ラビリンス", 25, "ヒューマン", 119301, "リノ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 32, 0, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 1, 14, "プリン大好きゴースト娘", "雨宮天", "B", "プリンを食べること", 130, "悪魔偽王国軍（ディアボロス）", 23, "魔族", 119901, "ミヤコ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 54, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 18, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "O", "家事全般", 168, "ラビリンス", 24, "ヒューマン", 120001, "シズル（ノワール）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "???", 0, "", 12, 14, "記憶喪失のドラゴン娘", "近藤玲奈", "B", "読書、ストレッチ", 147, "美食殿", 14, "ドラゴン族", 120701, "シェフィ（ニューイヤー）");
