INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 50, 0, "", 5, "??", "かつては夜を支配した最強の吸血鬼", "丹下桜", "A", "世界征服", 172, "悪魔偽王国軍（ディアボロス）", 5, "魔族", 120901, "イリヤ（ニューイヤー）");
