INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 39, 0, "", 9, 14, "行き倒れの謎のネコミミ魔法使い", "立花理香", "A", "猫と遊ぶ", 152, "美食殿", 2, "獣人族", 121101, "キャル（オーバーロード）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "??", 0, "", 7, 25, "秘密結社ラビリンスの『迷宮女王』", "沢城みゆき", "AB", "人間観察", 160, "ラビリンス", 25, "ヒューマン", 121201, "ラビリスタ（オーバーロード）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 40, 0, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 6, 12, "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "B", "観劇、おままごと", 150, "サレンディア救護院", 9, "ヒューマン", 121301, "クルミ（ステージ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 22, 0, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 1, 11, "ちょっとおませな恋に恋する女の子", "久野美咲", "A", "ファッション誌鑑賞、コスメ集め", 120, "ルーセント学院", 3, "魔族", 121401, "ミサキ（ステージ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 43, 0, "", 4, 16, "どこまでも一途に慕う、純情乙女", "大関英里", "O", "観察", 155, "ヴァイスフリューゲル　ランドソル支部", 7, "エルフ", 121501, "アユミ（怪盗）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 9, 13, "口が達者なヘタレドラゴン", "藤田茜", "AB", "ゲーム", 145, "ドラゴンズネスト", 29, "ドラゴン族", 121601, "イノリ（怪盗）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 45, 0, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 17, "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "A", "小説執筆", 159, "トワイライトキャラバン", 5, "魔族", 121901, "アンナ（パイレーツ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 42, 0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 18, "占いが得意な霊能少女", "大坪由佳", "AB", "占い", 157, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 122001, "シノブ（パイレーツ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 44, 0, "", 6, 13, "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "AB", "友達作りのイメトレ", 158, "フォレスティエ", 6, "エルフ", 122101, "アオイ（キャンプ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 55, 0, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 22, "純情でほっとけない大人の女性", "今井麻美", "A", "ウインドーショッピング", 164, "メルクリウス財団", 16, "エルフ", 122201, "ユカリ（キャンプ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 41, 0, "", 12, "??", "けんぞくのご主人様", "釘宮理恵", "AB", "お散歩、お料理", 149, "？？？", 6, "魔族", 122301, "ヴァンピィ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 44, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 16, "人助けが大好き！　前向き格闘娘", "東山奈央", "A", "人助け、応援", 155, "トゥインクルウィッシュ", 27, "獣人族", 122401, "ヒヨリ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 46, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 18, "クールで何事にも真っ直ぐな剣士", "早見沙織", "B", "読書、乗馬、お茶", 163, "トゥインクルウィッシュ", 12, "魔族", 122501, "レイ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 47, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 17, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "O", "料理、人間観察", 158, "トゥインクルウィッシュ", 5, "ヒューマン", 122601, "ユイ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 21, 0, "", 2, 8, "礼儀正しくしっかり者のちびっ子優等生", "小倉唯", "A", "お勉強", 118, "リトルリリカル", 2, "エルフ", 122701, "キョウカ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 27, 0, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 8, 9, "探検好きのイタズラっ子", "諸星すみれ", "O", "いたずら、探検", 128, "リトルリリカル", 10, "ヒューマン", 122801, "ミソギ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 21, 0, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 4, 10, "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "O", "かわいいもの集め", 117, "リトルリリカル", 3, "獣人族", 122901, "ミミ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "???", 0, "", "?", "??", "新たな姿で騎士の冒険を支え続ける妖精", "相坂優歌", "?", "？？？", 150, "？？？", "?", "？？？", 123001, "アメス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 42, 0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 16, "マホマホ王国のプリンセス", "内田真礼", "O", "空想、ぬいぐるみ集め", 155, "自警団（カォン）", 22, "獣人族", 123101, "マホ（エクスプローラー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 38, 0, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 5, 14, "ぷうきちといつも一緒！", "芹澤優", "B", "屋内でできる遊び", 148, "サレンディア救護院", 10, "ヒューマン", 123201, "アヤネ（エクスプローラー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, 55, 0, "", 6, 19, "ショタ大好き♪　ギャル系スライム娘", "和氣あず未", "B", "可愛いショタと遊ぶ、買い物", 157, "レイジ・レギオン", 13, "魔族？", 123301, "ネア");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 50, 0, "", 10, 25, "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "A", "格闘技、湯浴み", 171, "王宮騎士団（NIGHTMARE）", 25, "ヒューマン", 123401, "ジュン（キャンプ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 42, 0, "", 1, 17, "遊びと睡眠が何より大事なぐうたら娘", "小岩井ことり", "B", "あんパン", 144, "牧場（エリザベスパーク）", 1, "獣人族", 123501, "リン（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 43, 0, "", 8, 13, "義理堅くてからかい好きな剣術少女", "茅原実里", "A", "剣術、年長者をからかう", 149, "王宮騎士団（NIGHTMARE）", 11, "ヒューマン", 123601, "トモ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 55, 0, "", 8, 18, "オタク全開な魔法少女", "佳村はるか", "O", "読書、魔法", 166, "トワイライトキャラバン", 21, "魔族", 123701, "ナナカ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "??", 0, "", 2, 27, "傍若無人な王宮騎士団副団長", "たかはし智秋", "O", "強敵との闘争", 165, "王宮騎士団（NIGHTMARE）", 7, "ヒューマン", 123801, "クリスティーナ（ワイルド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 40, 0, "", 11, 12, "ヒーローに憧れる騎士見習いの少女", "下田麻美", "O", "ヒーローごっこ", 146, "王宮騎士団（NIGHTMARE）", 25, "獣人族", 123901, "マツリ（ワイルド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 42, 0, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 11, 13, "甘え上手なみんなの人気者", "浅倉杏美", "O", "サックス", 150, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 124001, "アカリ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 40, 0, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 11, 13, "人見知りであまのじゃくな女の子", "原紗友里", "O", "ゲーム全般", 150, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 124101, "ヨリ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 50, 0, "", 10, 25, "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "A", "格闘技、湯浴み", 171, "王宮騎士団（NIGHTMARE）", 25, "ヒューマン", 124201, "ジュン（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 4, 25, "妖しい微笑で全てを見透かす臥竜の頭領", "大西沙織", "O", "絵画、読書", 168, "ドラゴンズネスト", 17, "ドラゴン族", 124501, "ホマレ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 54, 0, "", 9, 21, "母性溢れる優しいみんなの「ミサト先生」", "國府田マリ子", "O", "絵本作り", 165, "フォレスティエ", 5, "エルフ", 124601, "ミサト（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 53, 0, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 3, 27, "実験が趣味の危険な科学者", "三石琴乃", "A", "研究、実験", 166, "トワイライトキャラバン", 7, "ヒューマン", 124701, "ミツキ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 40, 0, "", 1, 17, "歌って踊れる大人気アイドル", "日笠陽子", "B", "舞台鑑賞、ダンス", 157, "カルミナ", 24, "ヒューマン", 124801, "ノゾミ（リベレイター）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 6, 16, "拳で語る喧嘩屋ドラゴン少女", "小市眞琴", "B", "格闘技", 156, "ドラゴンズネスト", 25, "ドラゴン族", 124901, "カヤ（リベレイター）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 40, 0, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 8, 16, "さまよえる謎の少女", "潘めぐみ", "O", "冒険、思い出話", 148, "？？？", 11, "ヒューマン", 125001, "ムイミ（リベレイター）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 48, 0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 19, "弱きを助け強きをくじく猫娘", "沼倉愛美", "AB", "猫とたわむれること", 158, "メルクリウス財団", 1, "獣人族", 125101, "タマキ（カフェ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 33, 0, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 7, 17, "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "A", "お菓子屋通い", 140, "ヴァイスフリューゲル　ランドソル支部", 28, "ヒューマン", 125201, "モニカ（カフェ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 35, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11, "主を慕う、小さなガイド役", "伊藤美来", "B", "瞑想、動植物の飼育", 140, "美食殿", 11, "エルフ", 125301, "コッコロ（レンジャー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 40, 0, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11, 14, "読書が趣味の病弱少女", "小清水亜美", "A", "読書、お散歩", 153, "牧場（エリザベスパーク）", 3, "獣人族", 125401, "シオリ（レンジャー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 45, 0, "", 3, 17, "空への冒険を夢見る騎空士の少女", "金元寿子", "O", "冒険、おしゃべり", 156, "？？？", 10, "ヒューマン", 125501, "ジータ（ウォーロック）");
