INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (20, 42, 0, "", 11, 13, "忘れ難い罪過を抱える、黒き翼の聖女", "前田佳織里", "O", "お菓子作り、花の世話、バイオリン演奏", 147, "アルターメイデン", 1, "ヒューマン", 126001, "クリア（フォールン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (20, 34, 0, "", 3, 10, "正義の魂を受け継ぐ、爆食系天然天才娘", "高尾奏音", "O", "ごはんをたべること", 135, "アルターメイデン", 1, "獣人族", 126101, "プレシア（フォールン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 50, 0, "", 5, "??", "かつては夜を支配した最強の吸血鬼", "丹下桜", "A", "世界征服", 172, "悪魔偽王国軍（ディアボロス）", 5, "魔族", 126201, "イリヤ（儀装束）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 40, 0, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 10, 14, "ボクは誰よりも美しい", "大空直美", "AB", "鏡で自分を見ること", 150, "ヴァイスフリューゲル　ランドソル支部", 10, "エルフ", 126301, "ユキ（儀装束）");
