INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 45, 0, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 3, 18, "一人前の商人を目指すパワフルお嬢様", "松嵜麗", "AB", "慈善事業", 157, "メルクリウス財団", 12, "ヒューマン", 126701, "アキノ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 55, 0, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 22, "純情でほっとけない大人の女性", "今井麻美", "A", "ウインドーショッピング", 164, "メルクリウス財団", 16, "エルフ", 126801, "ユカリ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, 53, 0, "", 12, 20, "静寂を求め歌う陰気少女", "原田彩楓", "O", "歌、読書、詩を書くこと", 165, "レイジ・レギオン", 28, "魔族", 126901, "ランファ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 49, 0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 18, "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "AB", "小説を読むこと", 157, "ヴァイスフリューゲル　ランドソル支部", 19, "ヒューマン", 127001, "クウカ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 42, 0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 18, "占いが得意な霊能少女", "大坪由佳", "AB", "占い", 157, "悪魔偽王国軍（ディアボロス）", 22, "魔族", 127101, "シノブ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 39, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 14, "行き倒れの謎のネコミミ魔法使い", "立花理香", "A", "猫と遊ぶ", 152, "美食殿", 2, "獣人族", 127201, "キャル（編入生）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 48, 0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 4, 17, "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "O", "ファッション", 167, "ルーセント学院", 10, "魔族", 127301, "スズナ（編入生）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 17, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "A", "経営、お茶会", 156, "サレンディア救護院", 4, "エルフ", 127501, "サレン（サラサリア）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 54, 0, "", 7, 25, "人情味溢れる粋でいなせな「姉御」", "佐藤利奈", "B", "釣り", 167, "トワイライトキャラバン", 11, "ヒューマン", 127601, "ルカ（サラサリア）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "???", 0, "", 2, 12, "真面目で一生懸命なドラゴンメイド（姉）", "豊田萌絵", "?", "妹と過ごす休日", 145, "？？？", 5, "ドラゴン族", 127701, "リンド");
