INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 46, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 17, "いつも元気な腹ペコ少女", "M・A・O", "O", "食べ歩き、料理", 156, "美食殿", 31, "ヒューマン", 127901, "ペコリーヌ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 57, 0, "", 9, 26, "忠義に目覚めた女商人", "Lynn", "A", "お金を数えること、悪だくみ", 160, "リッチモンド商工会", 19, "ヒューマン", 128001, "クレジッタ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "???", 0, "", 9, 13, "口が達者なヘタレドラゴン", "藤田茜", "AB", "ゲーム", 145, "ドラゴンズネスト", 29, "ドラゴン族", 128301, "イノリ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 46, 0, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 12, 17, "みんなのために超能力を使う眠り姫", "大橋彩香", "A", "妹と遊ぶこと、二度寝、昼寝、早寝", 156, "フォレスティエ", 24, "エルフ", 128401, "ハツネ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 41, 0, "", 11, 15, "頭脳明晰な美少女名探偵", "水瀬いのり", "AB", "読書、推理", 152, "自警団（カォン）", 3, "獣人族", 128501, "カスミ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 44, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 16, "人助けが大好き！　前向き格闘娘", "東山奈央", "A", "人助け、応援", 155, "トゥインクルウィッシュ", 27, "獣人族", 128701, "ヒヨリ（アストラル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 46, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 18, "クールで何事にも真っ直ぐな剣士", "早見沙織", "B", "読書、乗馬、お茶", 163, "トゥインクルウィッシュ", 12, "魔族", 128801, "レイ（アストラル）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 47, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 17, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "O", "料理、人間観察", 158, "トゥインクルウィッシュ", 5, "ヒューマン", 128901, "ユイ（アストラル）");
