INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 54, 0, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 8, 17, "男勝りで情に厚いワイルド娘", "小松未可子", "O", "お菓子作り", 168, "自警団（カォン）", 9, "獣人族", 129801, "マコト（コマンダー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 43, 0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 16, "運命の相手に一途すぎる乙女", "橋本ちなみ", "B", "実験、裁縫、料理", 154, "トワイライトキャラバン", 30, "魔族", 129901, "エリコ（コマンダー）");
