INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 12, 15, "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "O", "ご奉仕", 154, "サレンディア救護院", 12, "ヒューマン", 130801, "スズメ（スプリング）");
