INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 42, 0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 16, "マホマホ王国のプリンセス", "内田真礼", "O", "空想、ぬいぐるみ集め", 155, "自警団（カォン）", 22, "獣人族", 131001, "マホ（ドリームパーク）");
