INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 43, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 17, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "A", "経営、お茶会", 156, "サレンディア救護院", 4, "エルフ", 133501, "サレン（ニューイヤー）");
