INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 46, 0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 17, "人々を守るために歌う、唱喚士の少女", "福原綾香", "O", "各種楽器", 163, "カルミナ", 3, "ヒューマン", 134401, "チカ（儀装束）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "全備重量278.1", 0, "", 11, "??", "スマイル満タン！　パワフル機械少女", "長谷川育美", "?", "昼寝、誰かの役に立つこと", 170, "？？？", 11, "機械人族", 134501, "クローチェ（エアリアル）");
