INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "???", 0, "", 12, 14, "記憶喪失のドラゴン娘", "近藤玲奈", "B", "読書、ストレッチ", 147, "美食殿", 14, "ドラゴン族", 135101, "シェフィ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (20, 34, 0, "", 3, 10, "正義の魂を受け継ぐ、爆食系天然天才娘", "高尾奏音", "O", "ごはんをたべること", 135, "アルターメイデン", 1, "獣人族", 135201, "プレシア（サマー）");
