INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 39, 0, "", 4, 13, "孤絶の香を纏う花の妖魔人", "立花日菜", "A", "花の手入れ、トゲぬき", 145, "？？？", 2, "妖魔人", 135401, "アネモネ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 3, "??", "太陽と熱砂の国で未来を願う笑顔の豪炎", "松岡由貴", "?", "人助け、街歩き、利き麦しゅわ", 162, "？？？", 27, "獣人族", 135501, "アイラ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 2, "??", "曙光と翠嵐の国で未来を護る寡黙な剣豪", "皆川純子", "?", "武器の手入れ、瞑想、釣り", 167, "？？？", 9, "魔族", 135601, "シナツ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 44, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 16, "人助けが大好き！　前向き格闘娘", "東山奈央", "A", "人助け、応援", 155, "トゥインクルウィッシュ", 27, "獣人族", 135701, "ヒヨリ（サラサリア）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 63, 0, "", 12, 19, "真白き冬化粧を纏う、一途な心の雪女", "天野聡美", "O", "三味線、死魔エナガのお世話", 179, "？？？", 30, "雪女", 135801, "ユキノ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 29, 0, "", 2, 20, "怪力無双、ハードボイルドな仁義の鬼嬢", "島袋美由利", "O", "強敵との手合わせ、夜廻り", 135, "？？？", 2, "鬼族", 135901, "サツキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 108, 0, "", 1, 28, "新たな道を歩み始めた女郎蜘蛛", "遠藤綾", "AB", "光を追うこと、整理整頓", 240, "？？？", 15, "妖魔人", 136001, "アラクネ");
