INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 53, 0, "", 2, 16, "落ちこぼれでもめげない、アルミラージ娘", "黒沢ともよ", "O", "巣ごもり、昼寝", 152, "？？？", 10, "妖魔人", 136201, "ナーナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, "??", 0, "", 7, 16, "明朗快活、なれど破滅に流るる溌溂少女", "鬼頭明里", "A", "特に無し", 159, "レイジ・レギオン", 2, "ヒューマン", 136301, "ミソラ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 47, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 17, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "O", "料理、人間観察", 158, "トゥインクルウィッシュ", 5, "ヒューマン", 136401, "ユイ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 54, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 18, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "O", "家事全般", 168, "ラビリンス", 24, "ヒューマン", 136501, "シズル（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 51, 0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 16, "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "O", "忍法開発", 163, "ヴァイスフリューゲル　ランドソル支部", 31, "ヒューマン", 137101, "ニノン（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 41, 0, "", 11, 15, "頭脳明晰な美少女名探偵", "水瀬いのり", "AB", "読書、推理", 152, "自警団（カォン）", 3, "獣人族", 137401, "カスミ（シスター）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 48, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11, "主を想い、“進化”したガイド役", "伊藤美来", "B", "瞑想、動植物の飼育", 164, "美食殿", 11, "エルフ", 137601, "コッコロ（嚮導幼君）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 44, 0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 15, "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "A", "お裁縫", 156, "ラビリンス", 25, "ヒューマン", 137901, "リノ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 49, 0, "", 2, 17, "冥府に咲くアンデッド系プリンセス", "長縄まりあ", "A", "香水集め、物語を読むこと", 158, "？？？", 21, "ヒューマン", 138001, "ヴァイオレット（イサナミ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 1, "??", "優しさと傲慢さを併せ持つプリンセス", "河瀬茉希", "?", "昼寝、新作スイーツの試食", 162, "？？？", 17, "天使族", 138101, "ライラエル（パルフェクト）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", "??", 0, "", 12, "??", "万魔の頂点、煉獄の媛君", "大久保瑠美", "?", "おままごと、人間観察", 139, "？？？", 31, "妖魔人", 138201, "ネフィ＝ネラ（鬼面仏心）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 46, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 17, "いつも元気な腹ペコ少女", "M・A・O", "O", "食べ歩き、料理", 156, "美食殿", 31, "ヒューマン", 138301, "ペコリーヌ（アストライア）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (21, 45, 0, "", 5, 16, "大変だけど元気です。盗賊ギルドの次女", "石見舞菜香", "A", "編み物", 158, "バンディ・シスターズ", 30, "ヒューマン", 138701, "ワカナ（ウィンター）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 40, 0, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11, 14, "読書が趣味の病弱少女", "小清水亜美", "A", "読書、お散歩", 153, "牧場（エリザベスパーク）", 3, "獣人族", 138801, "シオリ（ウィンター）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("", 0, 0, "", 10, 21, "怜悧で幽愁、オバケでオトボケな守護騎士", "富田美憂", "AB", "水墨画", 166, "？？？", 31, "ヒューマン", 138901, "グレイス（バニー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 21, 0, "", 2, 8, "礼儀正しくしっかり者のちびっ子優等生", "小倉唯", "A", "お勉強", 118, "リトルリリカル", 2, "エルフ", 139001, "キョウカ（ゴシック）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 44, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 16, "人助けが大好き！　前向き格闘娘", "東山奈央", "A", "人助け、応援", 155, "トゥインクルウィッシュ", 27, "獣人族", 180101, "ヒヨリ（プリンセス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 47, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 17, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "O", "料理、人間観察", 158, "トゥインクルウィッシュ", 5, "ヒューマン", 180201, "ユイ（プリンセス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 46, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 18, "クールで何事にも真っ直ぐな剣士", "早見沙織", "B", "読書、乗馬、お茶", 163, "トゥインクルウィッシュ", 12, "魔族", 180301, "レイ（プリンセス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 46, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 17, "いつも元気な腹ペコ少女", "M・A・O", "O", "食べ歩き、料理", 156, "美食殿", 31, "ヒューマン", 180401, "ぺコリーヌ（プリンセス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 35, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11, "主を慕う、小さなガイド役", "伊藤美来", "B", "瞑想、動植物の飼育", 140, "美食殿", 11, "エルフ", 180501, "コッコロ（プリンセス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 39, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 14, "行き倒れの謎のネコミミ魔法使い", "立花理香", "A", "猫と遊ぶ", 152, "美食殿", 2, "獣人族", 180601, "キャル（プリンセス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (500, "-", 0, "", "-", "-", "絆でつながる信愛の姉妹", "大橋彩香、小清水亜美", "-", "二人でピクニックに行くこと", "-", "フォレスティエ、牧場（エリザベスパーク）", "-", "エルフ、獣人族", 180701, "ハツネ＆シオリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "-", 0, "", "-", "-", "勇気！　友情！　リリカルズ！", "諸星すみれ、日高里菜、小倉唯", "-", "みんなで冒険すること", "-", "リトルリリカル", "-", "ヒューマン、獣人族、エルフ", 180801, "ミソギ＆ミミ＆キョウカ");
