INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 46, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 18, "クールで何事にも真っ直ぐな剣士", "早見沙織", "B", "読書、乗馬、お茶", 163, "トゥインクルウィッシュ", 12, "魔族", 928801, "レイ（アストラル）");
